def _validate_labels(labels: Dict[str, Any]):
    errors = []

    # Expresión regular para validar claves de etiquetas
    key_regex = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')

    for key, value in labels.items():
        # Validar la clave
        if not isinstance(key, str) or not key_regex.match(key):
            errors.append({str(key): f"La clave de la etiqueta '{key}' no coincide con la expresión regular"})

        # Validar el valor
        if not isinstance(value, (str, bytes)):
            errors.append({str(value): 'se esperaba un objeto de tipo cadena o bytes'})

    if errors:
        raise ValidationError(errors)

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Junto con la función :func:`generate_default_observer_schema_list`, esta función se llama de manera recursiva para generar parte de un ``observer_schema`` predeterminado a partir de una parte de un recurso de Kubernetes, definido respectivamente por ``manifest_dict`` o ``manifest_list``.

    Argumentos:
    **manifest_dict (dict):** Recursos parciales de Kubernetes.
    **first_level (bool, opcional):** Si es True, indica que el diccionario representa el esquema completo del observador (observer schema) de un recurso de Kubernetes.

    Retorna:
    **dict:** Esquema parcial generado (`observer_schema`).

    Esta función crea un nuevo diccionario a partir de ``manifest_dict`` y reemplaza todos los valores que no sean listas (`list`) ni diccionarios (`dict`) por ``None``.

    En el caso de un diccionario de ``first_level`` (es decir, un ``observer_schema`` completo para un recurso), los valores de los campos identificadores se copian del archivo de manifiesto.
    """
    observer_schema = {}

    for key, value in manifest_dict.items():
        if isinstance(value, dict):
            observer_schema[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            observer_schema[key] = generate_default_observer_schema_list(value)
        else:
            if first_level and key in ['apiVersion', 'kind', 'metadata']:
                observer_schema[key] = value
            else:
                observer_schema[key] = None

    return observer_schema

def generate_default_observer_schema_list(manifest_list):
    """
    Junto con la función :func:`generate_default_observer_schema_dict`, esta función se llama de manera recursiva para generar parte de un ``observer_schema`` predeterminado a partir de una parte de un recurso de Kubernetes, definido respectivamente por ``manifest_dict`` o ``manifest_list``.

    Argumentos:
    **manifest_list (list):** Recursos parciales de Kubernetes.

    Retorna:
    **list:** Esquema parcial generado (`observer_schema`).

    Esta función crea una nueva lista a partir de ``manifest_list`` y reemplaza todos los valores que no sean listas (`list`) ni diccionarios (`dict`) por ``None``.
    """
    observer_schema = []

    for item in manifest_list:
        if isinstance(item, dict):
            observer_schema.append(generate_default_observer_schema_dict(item))
        elif isinstance(item, list):
            observer_schema.append(generate_default_observer_schema_list(item))
        else:
            observer_schema.append(None)

    return observer_schema

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Junto con :func:``update_last_applied_manifest_dict_from_resp``, esta
    función se llama de forma recursiva para actualizar un ``last_applied_manifest``
    parcial a partir de una respuesta parcial de Kubernetes.

    Argumentos:
        last_applied_manifest (list): ``last_applied_manifest`` parcial que se
            está actualizando.
        observer_schema (list): ``observer_schema`` parcial.
        response (list): respuesta parcial de la API de Kubernetes.

    Esta función recorre todos los campos observados e inicializa su valor en
    ``last_applied_manifest`` si aún no están presentes.
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)
            else:
                last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Junto con :func:``update_last_applied_manifest_list_from_resp``, esta
    función se llama de forma recursiva para actualizar un ``last_applied_manifest``
    parcial a partir de una respuesta parcial de Kubernetes.

    Argumentos:
        last_applied_manifest (dict): ``last_applied_manifest`` parcial que se está
            actualizando.
        observer_schema (dict): ``observer_schema`` parcial.
        response (dict): respuesta parcial de la API de Kubernetes.

    Excepciones:
        KeyError: Si el campo observado no está presente en la respuesta de Kubernetes.

    Esta función recorre todos los campos observados e inicializa su valor en
    ``last_applied_manifest`` si aún no están presentes.
    """
    for key, schema in observer_schema.items():
        if key not in response:
            raise KeyError(f"El campo observado '{key}' no está presente en la respuesta de Kubernetes.")

        if isinstance(schema, dict):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = {}
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[key], schema, response[key])
        elif isinstance(schema, list):
            if key not in last_applied_manifest:
                last_applied_manifest[key] = []
            update_last_applied_manifest_list_from_resp(last_applied_manifest[key], schema, response[key])
        else:
            if key not in last_applied_manifest:
                last_applied_manifest[key] = response[key]

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Función auxiliar para manejar la actualización de listas en el last_applied_manifest.
    """
    for i, item in enumerate(response):
        if i >= len(last_applied_manifest):
            last_applied_manifest.append({})
        if isinstance(observer_schema[0], dict):
            update_last_applied_manifest_dict_from_resp(last_applied_manifest[i], observer_schema[0], item)
        elif isinstance(observer_schema[0], list):
            update_last_applied_manifest_list_from_resp(last_applied_manifest[i], observer_schema[0], item)
        else:
            last_applied_manifest[i] = item

def generate_default_observer_schema(app):
    """
    Generar el esquema de observador predeterminado para cada recurso de Kubernetes presente en  
    ``spec.manifest`` para el cual no se haya especificado un esquema de observador personalizado.

    Argumentos:
    app(krake.data.kubernetes.Application): La aplicación para la cual se generará un esquema de observador predeterminado.
    """
    default_schema = {
        "type": "object",
        "properties": {
            "apiVersion": {"type": "string"},
            "kind": {"type": "string"},
            "metadata": {
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "namespace": {"type": "string"}
                },
                "required": ["name"]
            },
            "spec": {"type": "object"},
            "status": {"type": "object"}
        },
        "required": ["apiVersion", "kind", "metadata"]
    }

    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema'):
            resource.observer_schema = default_schema

    return app

