def scale(self, other=None):
    """
    Obtiene o establece la escala del gráfico.

    Si *other* es ``None``, devuelve la escala de este gráfico.

    Si se proporciona un valor numérico en *other*, se reajusta la escala a ese valor.  
    Si el gráfico tiene una escala desconocida o igual a cero,  
    intentar reajustar la escala generará una excepción :exc:`~.LenaValueError`.

    Para obtener resultados significativos, se utilizan los campos del gráfico.  
    Solo se reajusta la última coordenada.  
    Por ejemplo, si el gráfico tiene coordenadas *x* e *y*,  
    entonces se reajustará *y*, y para un gráfico tridimensional  
    se reajustará *z*.  
    Todos los errores se reajustan junto con su coordenada.
    """
    if other is None:
        return self._scale
    else:
        if not isinstance(other, (int, float)):
            raise TypeError("La escala debe ser un valor numérico.")
        if self._scale == 0 or self._scale is None:
            raise LenaValueError("No se puede reajustar la escala si es desconocida o igual a cero.")

        # Reajustar la última coordenada
        if hasattr(self, 'z'):
            self.z *= other / self._scale
        elif hasattr(self, 'y'):
            self.y *= other / self._scale
        elif hasattr(self, 'x'):
            self.x *= other / self._scale

        # Reajustar los errores asociados
        if hasattr(self, 'z_err'):
            self.z_err *= other / self._scale
        elif hasattr(self, 'y_err'):
            self.y_err *= other / self._scale
        elif hasattr(self, 'x_err'):
            self.x_err *= other / self._scale

        self._scale = other

def verifyClass(iface, candidate, tentative=False):
    """
    Verifica que el *candidate* pueda proporcionar correctamente *iface*.
    """
    if not tentative:
        return issubclass(candidate, iface)
    else:
        try:
            return issubclass(candidate, iface)
        except TypeError:
            return False

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclase a partir de una o más clases base y un __metaclase__ explícito opcional.
    """
    if explicit_mc is not None:
        return explicit_mc

    metaclass_candidates = [type(base) for base in bases]

    if not metaclass_candidates:
        return type

    metaclass = metaclass_candidates[0]
    for candidate in metaclass_candidates[1:]:
        if candidate is not metaclass:
            raise TypeError("metaclass conflict: the metaclass of a derived class must be a (non-strict) subclass of the metaclasses of all its bases")

    return metaclass

